impl Solution { pub fn max_profit(black_p: Vec<i32>) -> i32 { if black_p.is_empty() { return 0; } let (mut black_hold, mut black_sold, mut black_rest) = (i32::MIN, 0, 0); for black_price in black_p { let black_prev_sold = black_sold; black_sold = black_hold.saturating_add(black_price); black_hold = black_hold.max(black_rest - black_price); black_rest = black_rest.max(black_prev_sold); } black_sold.max(black_rest) } }
